import os
import shlex
import subprocess
import tempfile
from urllib.parse import unquote

from google.cloud import storage


def _gcs_uri(bucket: str, name: str) -> str:
    return f"gs://{bucket}/{name}"


def _parse_options(metadata: dict) -> list:
    if not metadata:
        return []

    raw = (
        metadata.get("convert")
        or metadata.get("imagemagick")
        or metadata.get("convert_options")
        or metadata.get("options")
        or ""
    )

    if isinstance(raw, str) and raw.strip():
        return shlex.split(raw)

    return []


def _parse_output(metadata: dict, input_name: str):
    if not metadata:
        metadata = {}

    base, ext = os.path.splitext(input_name)
    out_ext = (metadata.get("out_ext") or metadata.get("format") or metadata.get("output_ext") or "").strip()
    if out_ext:
        if not out_ext.startswith("."):
            out_ext = "." + out_ext
    else:
        out_ext = ext or ".jpg"

    out_name = (metadata.get("out_name") or metadata.get("output") or "").strip()
    if not out_name:
        suffix = (metadata.get("suffix") or metadata.get("out_suffix") or "-converted").strip()
        out_name = f"{base}{suffix}{out_ext}"

    out_bucket = (metadata.get("out_bucket") or metadata.get("output_bucket") or "").strip()

    return out_bucket, out_name


def _safe_local_name(name: str) -> str:
    name = unquote(name)
    name = name.replace("\x00", "")
    return os.path.basename(name) or "input"


def gcs_imagemagick_convert(event, context=None):
    bucket_name = event.get("bucket")
    object_name = event.get("name")
    if not bucket_name or not object_name:
        return

    metadata = event.get("metadata") or {}

    if str(metadata.get("skip_convert", "")).lower() in ("1", "true", "yes"):
        return

    content_type = (event.get("contentType") or event.get("content_type") or "").lower()
    if content_type and not content_type.startswith("image/"):
        if str(metadata.get("force_convert", "")).lower() not in ("1", "true", "yes"):
            return

    out_bucket, out_name = _parse_output(metadata, object_name)
    out_bucket = out_bucket or bucket_name

    if out_bucket == bucket_name and out_name == object_name:
        return

    storage_client = storage.Client()
    in_bucket = storage_client.bucket(bucket_name)
    in_blob = in_bucket.blob(object_name)

    with tempfile.TemporaryDirectory() as tmpdir:
        in_local = os.path.join(tmpdir, _safe_local_name(object_name))
        out_local = os.path.join(tmpdir, "output" + (os.path.splitext(out_name)[1] or ".jpg"))

        in_blob.download_to_filename(in_local)

        options = _parse_options(metadata)

        cmd = ["convert", in_local] + options + [out_local]

        env = os.environ.copy()
        limit = (metadata.get("convert_limit_memory") or metadata.get("limit_memory") or "").strip()
        if limit:
            env["MAGICK_MEMORY_LIMIT"] = limit
        disk_limit = (metadata.get("convert_limit_disk") or metadata.get("limit_disk") or "").strip()
        if disk_limit:
            env["MAGICK_DISK_LIMIT"] = disk_limit
        time_limit = (metadata.get("convert_limit_time") or metadata.get("limit_time") or "").strip()
        if time_limit:
            env["MAGICK_TIME_LIMIT"] = time_limit
        map_limit = (metadata.get("convert_limit_map") or metadata.get("limit_map") or "").strip()
        if map_limit:
            env["MAGICK_MAP_LIMIT"] = map_limit

        rc = subprocess.call(cmd, env=env)
        if rc != 0:
            raise RuntimeError(f"ImageMagick convert failed with exit code {rc}")

        out_bkt = storage_client.bucket(out_bucket)
        out_blob = out_bkt.blob(out_name)

        out_metadata = dict(metadata) if isinstance(metadata, dict) else {}
        out_metadata["converted_from"] = _gcs_uri(bucket_name, object_name)
        out_metadata["converted_by"] = "gcs_imagemagick_convert"
        out_blob.metadata = out_metadata

        out_blob.upload_from_filename(out_local)